import { GoogleGenAI, Type } from "@google/genai";

// Lazy initialization to prevent app crash on startup if environment variables aren't ready
let aiClient: GoogleGenAI | null = null;

const getAiClient = () => {
  if (!aiClient) {
    // Access process.env inside the function scope, not top-level
    const apiKey = process.env.API_KEY;

    // Initialize with provided key or fallback to prevent constructor error
    // The actual API call will fail gracefully if the key is invalid
    aiClient = new GoogleGenAI({ apiKey: apiKey || "" });
  }
  return aiClient;
};

export interface SongConcept {
  title: string;
  genre: string;
  mood: string;
  lyricsSnippet: string;
  instrumentationIdeas: string[];
}

export const generateSongConcept = async (
  vision: string,
  genre: string
): Promise<SongConcept> => {
  try {
    const ai = getAiClient();
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: `Generate a song concept based on the following vision: "${vision}" and genre: "${genre}". 
      Provide a catchy title, a mood description, a short snippet of lyrics (chorus), and some instrumentation ideas.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            genre: { type: Type.STRING },
            mood: { type: Type.STRING },
            lyricsSnippet: { type: Type.STRING },
            instrumentationIdeas: {
              type: Type.ARRAY,
              items: { type: Type.STRING },
            },
          },
          required: ["title", "genre", "mood", "lyricsSnippet", "instrumentationIdeas"],
        },
      },
    });

    const text = response.text;
    if (!text) {
        throw new Error("No response text from Gemini");
    }
    return JSON.parse(text) as SongConcept;
  } catch (error) {
    console.error("Error generating song concept:", error);
    throw error;
  }
};

export const editImage = async (base64Data: string, mimeType: string, prompt: string): Promise<string> => {
  try {
    const ai = getAiClient();
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          {
            inlineData: {
              data: base64Data,
              mimeType: mimeType,
            },
          },
          {
            text: prompt,
          },
        ],
      },
    });

    if (response.candidates && response.candidates[0].content && response.candidates[0].content.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData && part.inlineData.data) {
          return part.inlineData.data;
        }
      }
    }

    throw new Error("No image generated in response");
  } catch (error) {
    console.error("Error editing image:", error);
    throw error;
  }
};

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';
import './index.css';

// Simple Error Boundary to catch render crashes
class ErrorBoundary extends React.Component<{children: React.ReactNode}, {hasError: boolean, error: Error | null}> {
  constructor(props: {children: React.ReactNode}) {
    super(props);
    this.state = { hasError: false, error: null };
  }

  static getDerivedStateFromError(error: Error) {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, errorInfo: React.ErrorInfo) {
    console.error("Uncaught error:", error, errorInfo);
  }

  render() {
    if (this.state.hasError) {
      return (
        <div style={{ padding: '2rem', color: '#ef4444', fontFamily: 'sans-serif' }}>
          <h1>Something went wrong.</h1>
          <p>Please check the console for details.</p>
          <pre style={{ background: '#fef2f2', padding: '1rem', borderRadius: '0.5rem', overflow: 'auto' }}>
            {this.state.error?.toString()}
          </pre>
        </div>
      );
    }

    return this.props.children;
  }
}

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <ErrorBoundary>
      <App />
    </ErrorBoundary>
  </React.StrictMode>
);

import React, { useState } from 'react';
import { Navbar } from './components/Navbar';
import { Hero } from './components/Hero';
import { HowItWorks } from './components/HowItWorks';
import { Footer } from './components/Footer';
import { SongBuilderModal } from './components/SongBuilderModal';
import { CursorTrace } from './components/CursorTrace';
import { LoginModal } from './components/LoginModal';
import { CheckoutModal } from './components/CheckoutModal';
import { Pricing } from './components/Pricing';
import { TrustedBy } from './components/TrustedBy';
import { SongConcept } from './services/geminiService';

interface OrderItem {
  type: 'concept' | 'release';
  price: number;
  concept?: SongConcept;
}

function App() {
  const [isBuilderOpen, setIsBuilderOpen] = useState(false);
  const [isLoginOpen, setIsLoginOpen] = useState(false);
  const [isCheckoutOpen, setIsCheckoutOpen] = useState(false);

  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [selectedGenre, setSelectedGenre] = useState<string>('');
  const [selectedTier, setSelectedTier] = useState<'standard' | 'premium'>('standard');
  const [orderItem, setOrderItem] = useState<OrderItem | null>(null);

  const handleStartBuilder = (genre?: string, tier: 'standard' | 'premium' = 'standard') => {
    setSelectedGenre(genre || '');
    setSelectedTier(tier);
    setIsBuilderOpen(true);
  };

  const handleOrderSong = (concept: SongConcept) => {
    setIsBuilderOpen(false);
    // Determine price based on selected tier
    const price = selectedTier === 'premium' ? 99 : 49;
    setOrderItem({ 
      type: selectedTier === 'premium' ? 'release' : 'concept', 
      price, 
      concept 
    });
    setIsCheckoutOpen(true);
  };

  return (
    <div className="min-h-screen flex flex-col font-sans relative bg-slate-50">
      <CursorTrace />
      <Navbar 
        onLoginClick={() => setIsLoginOpen(true)}
        isLoggedIn={isLoggedIn}
      />

      <div id="home">
        <Hero onStartBuilder={() => handleStartBuilder(undefined, 'standard')} />
      </div>

      <TrustedBy />

      <div id="how-it-works">
        <HowItWorks />
      </div>

      <Pricing onSelectPlan={(tier) => handleStartBuilder(undefined, tier)} />

      <div id="contact">
        <Footer />
      </div>

      <SongBuilderModal 
        isOpen={isBuilderOpen} 
        onClose={() => setIsBuilderOpen(false)} 
        initialGenre={selectedGenre}
        selectedTier={selectedTier}
        onOrder={handleOrderSong}
      />

      <LoginModal 
        isOpen={isLoginOpen}
        onClose={() => setIsLoginOpen(false)}
        onLogin={() => setIsLoggedIn(true)}
      />

      <CheckoutModal
        isOpen={isCheckoutOpen}
        onClose={() => setIsCheckoutOpen(false)}
        item={orderItem}
      />
    </div>
  );
}

export default App;

